-- Auto-generated customer seed from Private Finance sheets (EMI_COMPLETE + Register_book).
-- Customer profiles + ibb images only. NO payment/EMI-paid history (imported separately).
-- Retailers matched by name; rows whose retailer name is absent are skipped (INSERT..SELECT).
-- IMEI is the unique key; ON CONFLICT (imei) DO NOTHING makes this re-runnable.
-- NOTE: inserting fires fn_generate_emi_schedule(), creating an UNPAID schedule per customer.
-- PREREQUISITE: apply migration 016 first (it adds month-end clamping to the EMI
--   generator). 46 of these customers have emi_due_day = 30; the ALTER below keeps
--   the insert from failing the old 1..28 constraint, but correct Feb scheduling
--   still needs migration 016's function.

BEGIN;

-- Ensure the due-day constraint allows up to 30 before inserting (matches migration 016).
ALTER TABLE customers DROP CONSTRAINT IF EXISTS customers_emi_due_day_check;
ALTER TABLE customers ADD CONSTRAINT customers_emi_due_day_check CHECK (emi_due_day BETWEEN 1 AND 30);


COMMIT;
